using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Agents.AI;

var configuration = new ConfigurationBuilder()
    .AddEnvironmentVariables()
    .Build();

var apiKey = configuration["OPENAI_API_KEY"]
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = configuration["OPENAI_MODEL"] ?? "gpt-4o-mini-2024-07-18";

var services = new ServiceCollection();

services.AddChatClient(builder => builder
    .UseOpenAIChatClient(modelId, new OpenAI.OpenAIClient(apiKey)));

var provider = services.BuildServiceProvider();
var chatClient = provider.GetRequiredService<IChatClient>();

// Define tools available to the agent
var researchTools = new ResearchTools();
var tools = new[] 
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.TakeNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

// Configure the agent with iteration limits and tool access
var agent = new ChatClientAgent(chatClient, new ChatClientAgentOptions
{
    Instructions = """
        You are a research agent. Your job is to research a topic thoroughly by:
        1. Searching the web for relevant information using the SearchWeb tool
        2. Taking notes on key findings using the TakeNote tool
        3. After gathering enough information, use GetNotes to review your notes
        4. Provide a comprehensive summary of your findings

        Always search for multiple aspects of the topic and take detailed notes.
        When you have enough information, summarize your findings clearly.
        """,
    Tools = tools,
});

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

// Get the research topic from the user
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var messages = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

await foreach (var response in agent.InvokeStreamingAsync(messages, options))
{
    if (response.Role == ChatRole.Assistant && !string.IsNullOrEmpty(response.Text))
    {
        Console.Write(response.Text);
    }
}

Console.WriteLine("\n\n--- Research Complete ---");

/// <summary>
/// Tools available to the research agent for web searching and note-taking.
/// </summary>
sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _httpClient = new();

    [Description("Searches the web for information on a given query. Returns search results as text.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  [Tool] Searching: \"{query}\"");

        try
        {
            // Use a public search API (DuckDuckGo instant answer API)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var response = await _httpClient.GetStringAsync(url);
            using var doc = System.Text.Json.JsonDocument.Parse(response);
            var root = doc.RootElement;

            var results = new List<string>();

            // Extract abstract
            var abstractText = root.GetProperty("Abstract").GetString();
            if (!string.IsNullOrEmpty(abstractText))
            {
                var source = root.GetProperty("AbstractSource").GetString();
                results.Add($"[{source}] {abstractText}");
            }

            // Extract related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var item in topics.EnumerateArray().Take(5))
                {
                    if (item.TryGetProperty("Text", out var text))
                    {
                        var t = text.GetString();
                        if (!string.IsNullOrEmpty(t))
                            results.Add(t);
                    }
                }
            }

            if (results.Count == 0)
                return $"No detailed results found for '{query}'. Try a different search term.";

            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Takes a note to remember an important finding during research.")]
    public string TakeNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  [Tool] Note taken ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieves all notes taken during the research session.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes taken yet.";

        Console.WriteLine($"  [Tool] Retrieving {_notes.Count} note(s)");
        var numbered = _notes.Select((n, i) => $"{i + 1}. {n}");
        return $"Research notes ({_notes.Count}):\n" + string.Join("\n", numbered);
    }
}

